; ===========================================================================
; Millipede (Atari, 1982) -- Full Annotated Disassembly
; 6502 @ 1.512 MHz
;
; ROM: 16KB ($4000-$7FFF), mirrored at $8000-$FFFF
; Generated by disasm_millipede.py
; ===========================================================================
;
; GAME STRUCTURE OVERVIEW
; ----------------------
; The main loop (game_main_loop) calls ~24 subroutines per frame:
;   1. attract_credit_display  - coin/credit handling, attract text
;   2. score_display            - render P1/P2/high scores to VRAM
;   3. game_active_gate         - check start button; N=1-->play, N=0-->attract
;   4. earom_save               - incremental EAROM high-score persistence
;   5. timed_play_logic         - timed play countdown / attract state
;   6. death_anim_handler       - death puff/decay + freeze timer
;   7. player_movement          - trackball --> player sprite position
;   8. ddt_bomb_spawner         - DDT bomb placement
;   9. bullet_move_collide      - bullet movement + hit detection
;  10. millipede_spawner         - spawn millipede segments
;  11. death_sound               - descending pitch death SFX
;  12. millipede_movement        - head/body AI (turns, drops, targeting)
;  13. extra_enemy_spawner       - spider/beetle/mosquito/flea by wave
;  14. spider_bee_movement       - sinusoidal pattern + proximity scoring
;  15. inchworm_handler           - horizontal crawler + mushroom damage
;  16. bee_dragonfly_handler      - animation + POKEY2 buzzing sound
;  17. mosquito_flea_spawner      - vertical dropper, creates mushrooms
;  18. swarm_enemy_logic          - earwig/swarm movement
;  19. ddt_cloud_expand           - DDT poison cloud growth
;  20. level_transition           - mushroom restoration between waves
;  21. wave_complete_check        - all enemies dead --> next wave
;  22. mushroom_field_regen       - restore damaged mushrooms
;  23. extra_life_check           - score vs threshold --> bonus life
;  24. mushroom_field_redraw      - full field rendering
;
; OBJECT SYSTEM (16 sprite slots, 6 parallel ZP arrays)
; -------------------------------------------------------
;   $00-$0F,X = tile/char code    $10-$1F,X = Y direction/speed
;   $20-$2F,X = X position        $30-$3F,X = Y position
;   $40-$4F,X = move speed/dir    $50-$5F,X = color + active flag
;
;   Slot 0:    Player shooter (tile $03) / DDT cloud ($10-$13)
;   Slots 1-11: Millipede segments + enemy reuse
;   Slot 12:   DDT bomb / overflow enemy
;   Slots 13-15: Bullets / special effects
;
; GAME STATE ($96): $FF=attract, $00=normal play, $01+=timed play
; PLAYER ACTIVE: $D3/$D4 = $FF means player not active; both $FF = attract
;
; ENEMY TYPES BY TILE:
;   $00-$07: Millipede segments (animated)    $08-$09: Head turning
;   $10-$13: DDT poison cloud (expanding)    $14-$1B: Beetle
;   $1C-$1D: Inchworm                        $1E-$1F: Spider
;   $34-$37: Swarm/earwig                    $38-$3A: Bee/dragonfly
;   $FA/$FF: Death puff animation
;
; ===========================================================================

; --- Hardware Equates ---

; POKEY 1 ($0400-$040F)
POKEY1_AUDF1    = $0400
POKEY1_AUDC1    = $0401
POKEY1_AUDF2    = $0402
POKEY1_AUDC2    = $0403
POKEY1_AUDF3    = $0404
POKEY1_AUDC3    = $0405
POKEY1_AUDF4    = $0406
POKEY1_AUDC4    = $0407
POKEY1_AUDCTL   = $0408     ; write: AUDCTL / read: ALLPOT (DSW1)
POKEY1_STIMER   = $0409
POKEY1_RANDOM   = $040A     ; read: random number
POKEY1_POTGO    = $040B
POKEY1_IRQEN    = $040E     ; write: IRQEN / read: IRQST
POKEY1_SKCTL    = $040F     ; write: SKCTL / read: SKSTAT

; POKEY 2 ($0800-$080F)
POKEY2_AUDF1    = $0800
POKEY2_AUDC1    = $0801
POKEY2_AUDF2    = $0802
POKEY2_AUDC2    = $0803
POKEY2_AUDF3    = $0804
POKEY2_AUDC3    = $0805
POKEY2_AUDF4    = $0806
POKEY2_AUDC4    = $0807
POKEY2_AUDCTL   = $0808
POKEY2_STIMER   = $0809
POKEY2_RANDOM   = $080A
POKEY2_POTGO    = $080B
POKEY2_IRQEN    = $080E
POKEY2_SKCTL    = $080F

; Input Ports
IN0             = $2000     ; P1 inputs / VBLANK (bit 6)
IN1             = $2001     ; P2 inputs / trackball Y
IN2             = $2010     ; joystick / coin / tilt
IN3             = $2011     ; self-test / cabinet

; Other I/O
EAROM_READ      = $2030     ; EAROM data read
PALETTE_BASE    = $2480     ; palette RAM ($2480-$249F, 32 bytes)
OUT_LATCH_0     = $2500     ; output latch 0
OUT_LATCH_1     = $2501     ; output latch 1
OUT_LATCH_2     = $2502     ; output latch 2
OUT_LATCH_3     = $2503     ; output latch 3
OUT_LATCH_4     = $2504     ; output latch 4
OUT_TBEN        = $2505     ; trackball enable (D7)
OUT_FLIP        = $2506     ; flip screen (D7)
OUT_INT_ACK     = $2507     ; interrupt acknowledge (D7)
IRQ_ACK         = $2600     ; IRQ acknowledge (write any value)
WATCHDOG        = $2680     ; watchdog reset
EAROM_CTRL      = $2700     ; EAROM control latch (ER2055)
;                             ;   b0=CK (clock), b1=/C1, b2=C2, b3=CS1
;                             ;   READ=$08, WRITE=$06, STANDBY=$00
;                             ;   +CS1 (b3) to select chip; +CK (b0) to clock
EAROM_WRITE     = $2780     ; EAROM address+data latch ($2780-$27BF)

; Memory Map
RAM_START       = $0000
RAM_END         = $03FF
VRAM_START      = $1000     ; 960 bytes of video RAM
VRAM_END        = $13BF
SPRITE_RAM      = $13C0     ; 64 bytes, 16 sprites x 4
SPRITE_RAM_END  = $13FF
ROM_START       = $4000

; --- Zero-Page Game Variables ---
game_state      = $96       ; $FF=attract, $00=normal, $01+=timed
current_player  = $98       ; 0=P1, 1=P2
vblank_flag     = $9A       ; set by IRQ, cleared by main loop
p1_lives        = $A5       ; P1 lives remaining
p2_lives        = $A6       ; P2 lives remaining
p1_segments     = $AB       ; millipede segments to kill (P1)
p1_score_lo     = $B6       ; P1 score low (BCD)
p1_score_mid    = $B8       ; P1 score mid (BCD)
p1_score_hi     = $BA       ; P1 score high + wave counter (BCD)
p1_active       = $D3       ; $FF=not playing, else active
p2_active       = $D4       ; $FF=not playing, else active
credit_count    = $D9       ; number of credits
flip_screen     = $EF       ; $00=normal, $80=cocktail P2
dip_switch_1    = $F7       ; DSW1 (coinage, bonus)
dip_switch_2    = $E4       ; DSW2 (lives, difficulty)

; --- RAM Variables ($0200+) ---
death_timer     = $02CB     ; nonzero = player dying (countdown)
freeze_timer    = $02CE     ; nonzero = game frozen (death anim)
ddt_bombs_left  = $02CA     ; DDT bombs available
field_active    = $0305     ; nonzero = mushroom field needs redraw

; Vectors (at $7FFA-$7FFF, mirrored to $FFFA-$FFFF)
;   NMI:   $7FF6
;   RESET: $7929
;   IRQ:   $7643

; Indirect JMP targets (jump tables):
;   JMP ($00B5)
;   JMP ($0103)
;   JMP ($024C)
;   JMP ($02F0)
;   JMP ($0AAD)
;   JMP ($44F0)
;   JMP ($52F0)
;   JMP ($79BD)
;   JMP ($98A6)
;   JMP ($A885)
;   JMP ($C0D0)
;   JMP ($E525)


    .org $4000


cold_start:
                                    ; ASCII: "L)y    COPYRIGHT ATARI 1982     "
    .byte $4C,$29,$79,$20,$20,$20,$20,$43,$4F,$50,$59,$52,$49

L400D:
    .byte $47,$48,$54,$20,$41,$54,$41,$52,$49,$20,$31,$39,$38,$32,$20,$20 ; $400D
    .byte $20,$A0

; ============================================================
; Main game loop entry point. Called after RESET initialization.
; Calls frame_init once, then loops on wait_vblank calling ~24
; subroutines per frame for all game logic.
; ============================================================
game_main_loop:
    JSR frame_init                  ; 401F: 20 00 49
    CLI                             ; 4022: 58
    JSR display_init                ; 4023: 20 0E 62

; ============================================================
; Per-frame VBLANK wait loop. Spins on $9A (set by IRQ handler).
; After VBLANK: watchdog, self-test check, then all game subsystems.
; ============================================================
wait_vblank:
    LSR $9A                         ; 4026: 46 9A  ; vblank_flag
    BCC wait_vblank                 ; 4028: 90 FC
    STA $2680                       ; 402A: 8D 80 26  ; WATCHDOG
    BIT $2011                       ; 402D: 2C 11 20  ; IN3

L4030:
    BPL L4030                       ; 4030: 10 FE  ; <<< SPIN LOOP (safety/watchdog catch)
    JSR attract_credit_display      ; 4032: 20 92 55
    JSR score_display               ; 4035: 20 5A 61
    JSR game_active_gate            ; 4038: 20 A4 57
    BPL wait_vblank                 ; 403B: 10 E9
    JSR earom_save                  ; 403D: 20 E5 78
    JSR timed_play_logic            ; 4040: 20 73 5D
    BCS wait_vblank                 ; 4043: B0 E1
    JSR death_anim_handler          ; 4045: 20 FC 45
    JSR player_movement             ; 4048: 20 9F 4C
    JSR ddt_bomb_spawner            ; 404B: 20 A7 43
    JSR bullet_move_collide         ; 404E: 20 C5 4D
    JSR millipede_spawner           ; 4051: 20 35 59  ; spawn new segments if needed
    LDA $02CB                       ; 4054: AD CB 02  ; death_timer - player dying?
    BEQ L405E                       ; 4057: F0 05  ; no -> process enemies
    JSR death_sound                 ; 4059: 20 CA 50  ; play death explosion sound
    BCS L4076                       ; 405C: B0 18  ; skip enemy logic during death

L405E:                                              ; --- enemy movement subsystems ---
    JSR millipede_movement          ; 405E: 20 21 4B  ; move all millipede segments
    JSR extra_enemy_spawner         ; 4061: 20 05 51  ; spawn bonus enemies
    JSR spider_bee_movement         ; 4064: 20 E8 47  ; move spiders and bees
    JSR inchworm_handler            ; 4067: 20 4F 45  ; process inchworm (slow all enemies)
    JSR bee_dragonfly_handler       ; 406A: 20 8E 40  ; process bee/dragonfly
    JSR mosquito_flea_spawner       ; 406D: 20 31 4A  ; spawn mosquitoes/fleas
    JSR swarm_enemy_logic           ; 4070: 20 CD 41  ; handle swarm attack waves
    JSR ddt_cloud_expand            ; 4073: 20 10 53  ; expand DDT poison clouds

L4076:                                              ; --- end-of-frame housekeeping ---
    JSR level_transition            ; 4076: 20 DC 61  ; handle level/wave transitions
    JSR wave_complete_check         ; 4079: 20 EC 53  ; check if all segments killed
    JSR mushroom_field_regen        ; 407C: 20 03 5A  ; between-wave mushroom regen
    JSR extra_life_check            ; 407F: 20 4B 5B  ; award extra life at threshold
    LDA $0305                       ; 4082: AD 05 03  ; field_proc_active
    BEQ wait_vblank                 ; 4085: F0 9F  ; no field work -> next frame
    JSR mushroom_field_redraw       ; 4087: 20 78 68  ; continue field scan/repair
    JMP wait_vblank                 ; 408A: 4C 26 40  ; loop to next frame
    .byte $EA

; ============================================================
; Bee/dragonfly handler. Animates bee sprites (tiles $38-$3A),
; manages their sinusoidal movement, and drives POKEY2 channel 4
; for the buzzing sound effect. Iterates object slots 0-12.
; ============================================================
bee_dragonfly_handler:
    LDA $0F                         ; 408E: A5 0F  ; player_tile
    EOR #$0A                        ; 4090: 49 0A  ; tile $0A = player alive?
    ORA $02CE                       ; 4092: 0D CE 02  ; freeze_timer
    BEQ L4098                       ; 4095: F0 01  ; skip if dead or frozen
    RTS                             ; 4097: 60

L4098:
    LDA $5C                         ; 4098: A5 5C
    BNE L40B8                       ; 409A: D0 1C
    LDX $98                         ; 409C: A6 98  ; current_player
    LDA $AB,X                       ; 409E: B5 AB  ; p1_segments
    LDY $A5,X                       ; 40A0: B4 A5  ; p1_lives
    BNE L40AC                       ; 40A2: D0 08
    LDY $F9                         ; 40A4: A4 F9  ; swarm_active_cnt
    BEQ L40AC                       ; 40A6: F0 04
    CMP #$0A                        ; 40A8: C9 0A
    BCS L40B3                       ; 40AA: B0 07

L40AC:
    JSR get_spawn_threshold         ; 40AC: 20 5E 41
    CMP $E8,X                       ; 40AF: D5 E8  ; p1_mush_kills

L40B1:
    BCC L40B8                       ; 40B1: 90 05

L40B3:
    LDX #$0C                        ; 40B3: A2 0C
    JSR spawn_enemy_slot            ; 40B5: 20 79 41

L40B8:
    LDX #$0C                        ; 40B8: A2 0C
    LDA #$FF                        ; 40BA: A9 FF
    STA $9C                         ; 40BC: 85 9C  ; temp_9C

L40BE:
    LDA $50,X                       ; 40BE: B5 50
    BEQ L40F0                       ; 40C0: F0 2E
    LDA $00,X                       ; 40C2: B5 00  ; get tile ID
    CMP #$3A                        ; 40C4: C9 3A  ; tile >= $3A? not a bee
    BCS L40F0                       ; 40C6: B0 28
    CMP #$38                        ; 40C8: C9 38  ; tile < $38? not a bee
    BCC L40F0                       ; 40CA: 90 24  ; $38-$39 = bee animation frames
    LDA $62                         ; 40CC: A5 62  ; timer_lo
    AND #$01                        ; 40CE: 29 01

L40D0:
    BNE L40D8                       ; 40D0: D0 06
    LDA $00,X                       ; 40D2: B5 00
    EOR #$01                        ; 40D4: 49 01
    STA $00,X                       ; 40D6: 95 00

L40D8:
    LDA $30,X                       ; 40D8: B5 30
    EOR $F1                         ; 40DA: 45 F1  ; x_flip_xor
    LSR A                           ; 40DC: 4A
    EOR #$FF                        ; 40DD: 49 FF
    ORA #$80                        ; 40DF: 09 80
    CMP $9C                         ; 40E1: C5 9C  ; temp_9C
    BCS L40E7                       ; 40E3: B0 02
    STA $9C                         ; 40E5: 85 9C  ; temp_9C

L40E7:
    LDA #$01                        ; 40E7: A9 01
    STA $C7                         ; 40E9: 85 C7  ; sound_trigger
    JSR bee_movement_tick           ; 40EB: 20 F9 40
    BCC L40F8                       ; 40EE: 90 08

L40F0:
    DEX                             ; 40F0: CA
    BPL L40BE                       ; 40F1: 10 CB
    LDA $9C                         ; 40F3: A5 9C  ; temp_9C
    STA $0806                       ; 40F5: 8D 06 08  ; POKEY2_AUDF4

L40F8:
    RTS                             ; 40F8: 60

; ============================================================
; Single bee movement tick. Updates Y/X position for one bee slot.
; Checks field collision and screen boundaries.
; ============================================================
bee_movement_tick:
    LDA $20,X                       ; 40F9: B5 20
    STA $9B                         ; 40FB: 85 9B  ; temp_9B
    LDA $30,X                       ; 40FD: B5 30
    SEC                             ; 40FF: 38
    SBC $40,X                       ; 4100: F5 40
    STA $30,X                       ; 4102: 95 30
    EOR $F0                         ; 4104: 45 F0  ; y_flip_xor
    CMP #$04                        ; 4106: C9 04
    BCC bee_boundary_check          ; 4108: 90 49
    JSR check_field_collision       ; 410A: 20 47 4D
    BCC L4152                       ; 410D: 90 43
    LDA #$04                        ; 410F: A9 04
    EOR $F1                         ; 4111: 45 F1  ; x_flip_xor
    CLC                             ; 4113: 18
    ADC $30,X                       ; 4114: 75 30
    LDY #$00                        ; 4116: A0 00
    JSR xy_to_vram                  ; 4118: 20 9C 59
    JSR check_mushroom_range        ; 411B: 20 A0 4E
    BCS L4152                       ; 411E: B0 32

L4120:
    BIT $96                         ; 4120: 24 96  ; game_state
    BMI L4129                       ; 4122: 30 05
    LDA $02CA                       ; 4124: AD CA 02  ; ddt_bombs_left
    BNE L4151                       ; 4127: D0 28

L4129:
    LDA $62                         ; 4129: A5 62  ; timer_lo
    AND #$03                        ; 412B: 29 03

L412D:
    BNE L4151                       ; 412D: D0 22
    LDY $00,X                       ; 412F: B4 00
    CPY #$20                        ; 4131: C0 20

L4133:
    BCS L4143                       ; 4133: B0 0E
    LDA $30,X                       ; 4135: B5 30
    EOR $F1                         ; 4137: 45 F1  ; x_flip_xor
    CMP #$48                        ; 4139: C9 48
    LDA #$01                        ; 413B: A9 01
    BCS L4145                       ; 413D: B0 06
    LDA #$07                        ; 413F: A9 07
    BNE L4145                       ; 4141: D0 02

L4143:
    LDA #$03                        ; 4143: A9 03

L4145:
    AND $080A                       ; 4145: 2D 0A 08  ; POKEY2_RANDOM

L4148:
    BNE L4151                       ; 4148: D0 07

L414A:
    STX $9B                         ; 414A: 86 9B  ; temp_9B
    JSR place_mushroom              ; 414C: 20 F5 58
    LDX $9B                         ; 414F: A6 9B  ; temp_9B

L4151:
    SEC                             ; 4151: 38

L4152:
    RTS                             ; 4152: 60

; ------------------------------------------------------------
bee_boundary_check:
    LDA #$00                        ; 4153: A9 00
    STA $02DE,X                     ; 4155: 9D DE 02  ; obj_anim_state
    STA $50,X                       ; 4158: 95 50
    STA $20,X                       ; 415A: 95 20
    SEC                             ; 415C: 38
    RTS                             ; 415D: 60

; ------------------------------------------------------------
get_spawn_threshold:
    LDA $BA,X                       ; 415E: B5 BA  ; p1_score_hi
    CMP #$02                        ; 4160: C9 02

L4162:
    LDY #$05                        ; 4162: A0 05
    BCC L4168                       ; 4164: 90 02
    LDY #$09                        ; 4166: A0 09

L4168:
    CMP #$12                        ; 4168: C9 12
    BCC L4177                       ; 416A: 90 0B
    LSR A                           ; 416C: 4A
    CLC                             ; 416D: 18
    ADC #$06                        ; 416E: 69 06
    CMP #$30                        ; 4170: C9 30

L4172:
    BCC L4176                       ; 4172: 90 02
    LDA #$2F                        ; 4174: A9 2F

L4176:
    TAY                             ; 4176: A8

L4177:
    TYA                             ; 4177: 98
    RTS                             ; 4178: 60

; ------------------------------------------------------------
spawn_enemy_slot:
    STX $9B                         ; 4179: 86 9B  ; temp_9B
    LDX $98                         ; 417B: A6 98  ; current_player

L417D:
    LDA #$03                        ; 417D: A9 03
    LDY $BA,X                       ; 417F: B4 BA  ; p1_score_hi
    LDX $9B                         ; 4181: A6 9B  ; temp_9B
    CPY #$06                        ; 4183: C0 06
    BCS L41A1                       ; 4185: B0 1A
    LDY #$10                        ; 4187: A0 10
    LDA #$57                        ; 4189: A9 57

L418B:
    EOR $6316,Y                     ; 418B: 59 16 63
    DEY                             ; 418E: 88
    BPL L418B                       ; 418F: 10 FA
    TAY                             ; 4191: A8
    BEQ L419F                       ; 4192: F0 0B
    LDX $98                         ; 4194: A6 98  ; current_player
    LDA $B6,X                       ; 4196: B5 B6  ; p1_score_lo
    LDX $9B                         ; 4198: A6 9B  ; temp_9B
    CMP #$90                        ; 419A: C9 90
    BCC L419F                       ; 419C: 90 01
    SED                             ; 419E: F8

L419F:
    LDA #$02                        ; 419F: A9 02

L41A1:
    BIT $EF                         ; 41A1: 24 EF  ; flip_screen
    BPL L41A8                       ; 41A3: 10 03
    JSR negate_a                    ; 41A5: 20 00 76

L41A8:
    STA $40,X                       ; 41A8: 95 40  ; Y speed
    LDA #$38                        ; 41AA: A9 38  ; tile $38 = bee/dragonfly
    STA $00,X                       ; 41AC: 95 00

; ------------------------------------------------------------
; Initialize enemy at top of screen with random X position.
init_enemy_position:
    LDA #$F8                        ; 41AE: A9 F8
    EOR $F0                         ; 41B0: 45 F0  ; y_flip_xor
    STA $30,X                       ; 41B2: 95 30

L41B4:
    LDA $040A                       ; 41B4: AD 0A 04  ; POKEY1_RANDOM
    AND #$F8                        ; 41B7: 29 F8
    BEQ L41B4                       ; 41B9: F0 F9
    CMP #$10                        ; 41BB: C9 10
    BCC L41B4                       ; 41BD: 90 F5
    SEC                             ; 41BF: 38

L41C0:
    SBC #$04                        ; 41C0: E9 04
    STA $20,X                       ; 41C2: 95 20
    LDA #$00                        ; 41C4: A9 00
    STA $10,X                       ; 41C6: 95 10
    LDA #$79                        ; 41C8: A9 79
    STA $50,X                       ; 41CA: 95 50
    RTS                             ; 41CC: 60

; ============================================================
; Swarm/earwig enemy logic. Handles tiles $34-$37 (4-frame anim).
; Swarm enemies move in packs, changing direction at field edges.
; ============================================================
swarm_enemy_logic:
    LDA $0F                         ; 41CD: A5 0F  ; player_tile
    EOR #$0A                        ; 41CF: 49 0A
    ORA $02CE                       ; 41D1: 0D CE 02  ; freeze_timer
    BEQ L41D7                       ; 41D4: F0 01

L41D6:
    RTS                             ; 41D6: 60

L41D7:
    LDA $FA                         ; 41D7: A5 FA  ; max_swarm
    BEQ L4259                       ; 41D9: F0 7E
    LDX $98                         ; 41DB: A6 98  ; current_player
    LDA $BA,X                       ; 41DD: B5 BA  ; p1_score_hi
    CMP #$60                        ; 41DF: C9 60
    LDA #$7F                        ; 41E1: A9 7F
    BCC L41E7                       ; 41E3: 90 02
    LDA #$3F                        ; 41E5: A9 3F

L41E7:
    AND $62                         ; 41E7: 25 62  ; timer_lo
    EOR #$37                        ; 41E9: 49 37
    BNE L4259                       ; 41EB: D0 6C

L41ED:
    LDX $98                         ; 41ED: A6 98  ; current_player
    LDA $A5,X                       ; 41EF: B5 A5  ; p1_lives
    BEQ L4259                       ; 41F1: F0 66
    LDA $AB,X                       ; 41F3: B5 AB  ; p1_segments
    CMP #$0C                        ; 41F5: C9 0C
    BCS L4259                       ; 41F7: B0 60
    LDA $F7                         ; 41F9: A5 F7  ; dip_switch_1
    AND #$02                        ; 41FB: 29 02
    BNE L4203                       ; 41FD: D0 04

L41FF:
    LDA $A7                         ; 41FF: A5 A7  ; spawn_request
    BNE L4259                       ; 4201: D0 56

L4203:
    LDA $BA,X                       ; 4203: B5 BA  ; p1_score_hi
    CMP #$09                        ; 4205: C9 09
    LDX #$01                        ; 4207: A2 01
    BCC L4211                       ; 4209: 90 06
    INX                             ; 420B: E8
    CMP #$25                        ; 420C: C9 25
    BCC L4211                       ; 420E: 90 01
    INX                             ; 4210: E8

L4211:
    CPX $F9                         ; 4211: E4 F9  ; swarm_active_cnt
    BEQ L4259                       ; 4213: F0 44
    LDX #$0C                        ; 4215: A2 0C

L4217:
    DEX                             ; 4217: CA
    BMI L4259                       ; 4218: 30 3F
    LDA $50,X                       ; 421A: B5 50
    BNE L4217                       ; 421C: D0 F9
    INC $F9                         ; 421E: E6 F9  ; swarm_active_cnt
    DEC $FA                         ; 4220: C6 FA  ; max_swarm
    LDA #$B9                        ; 4222: A9 B9
    STA $50,X                       ; 4224: 95 50
    LDA #$48                        ; 4226: A9 48
    EOR $F0                         ; 4228: 45 F0  ; y_flip_xor
    STA $30,X                       ; 422A: 95 30
