    BCC L4B3D                       ; 4B37: 90 04

L4B39:
    DEX                             ; 4B39: CA
    BPL L4B2F                       ; 4B3A: 10 F3

L4B3C:
    RTS                             ; 4B3C: 60

L4B3D:
    LDA $62                         ; 4B3D: A5 62  ; timer_lo
    AND #$01                        ; 4B3F: 29 01
    BNE L4B4C                       ; 4B41: D0 09
    LDA $00,X                       ; 4B43: B5 00  ; get tile code
    CLC                             ; 4B45: 18
