    AND #$07                        ; 4B48: 29 07  ; wrap 0-7 (8 body frames)
    STA $00,X                       ; 4B4A: 95 00

L4B4C:
    LDY #$01                        ; 4B4C: A0 01
    LDA $30,X                       ; 4B4E: B5 30
    EOR $F0                         ; 4B50: 45 F0  ; y_flip_xor
    CMP #$09                        ; 4B52: C9 09
