; ============================================================
; Player movement. Reads trackball accumulators ($CC/$CD, set by IRQ),
; clamps delta to +/-8 via clamp_trackball, updates player position
; ($2F=Y, $3F=X). Collision-checks new position via xy_to_vram;
; if tile != 0, movement is blocked. Clamps Y to $0B-$F4.
; ============================================================
player_movement:
    LDA $96                         ; 4C9F: A5 96  ; game_state
    BPL L4CA4                       ; 4CA1: 10 01

L4CA3:
    RTS                             ; 4CA3: 60

L4CA4:
    LDA $0F                         ; 4CA4: A5 0F  ; player_tile
    EOR #$0A                        ; 4CA6: 49 0A
    ORA $02CE                       ; 4CA8: 0D CE 02  ; freeze_timer
    BNE L4CA3                       ; 4CAB: D0 F6
    LDA $3F                         ; 4CAD: A5 3F  ; player_xpos
    STA $9D                         ; 4CAF: 85 9D
    LDY #$00                        ; 4CB1: A0 00
    LDA $CC                         ; 4CB3: A5 CC  ; trackball_accum_x
    STY $CC                         ; 4CB5: 84 CC  ; trackball_accum_x
    JSR clamp_trackball             ; 4CB7: 20 83 60
    ADC $60                         ; 4CBA: 65 60  ; trackball_frac_x
    STA $60                         ; 4CBC: 85 60  ; trackball_frac_x
    TYA                             ; 4CBE: 98
    ADC $2F                         ; 4CBF: 65 2F  ; player_ypos
    TAX                             ; 4CC1: AA
    STA $9B                         ; 4CC2: 85 9B  ; temp_9B
    LDY #$00                        ; 4CC4: A0 00
    LDA $3F                         ; 4CC6: A5 3F  ; player_xpos
    JSR xy_to_vram                  ; 4CC8: 20 9C 59
    BNE L4CDE                       ; 4CCB: D0 11
    TXA                             ; 4CCD: 8A
    CMP #$F4                        ; 4CCE: C9 F4  ; top boundary (row 30)
    BCC L4CD6                       ; 4CD0: 90 04
    LDA #$F4                        ; 4CD2: A9 F4  ; clamp to top edge
    BNE L4CE0                       ; 4CD4: D0 0A

L4CD6:
    CMP #$0B                        ; 4CD6: C9 0B  ; bottom boundary (player zone)
    BCS L4CE0                       ; 4CD8: B0 06
    LDA #$0B                        ; 4CDA: A9 0B  ; clamp to bottom edge
    BNE L4CE0                       ; 4CDC: D0 02

L4CDE:
    LDA $2F                         ; 4CDE: A5 2F  ; player_ypos

L4CE0:
    STA $2F                         ; 4CE0: 85 2F  ; player_ypos
    LDY $96                         ; 4CE2: A4 96  ; game_state
    BPL L4CE7                       ; 4CE4: 10 01
    RTS                             ; 4CE6: 60

L4CE7:
    LDY #$00                        ; 4CE7: A0 00
    LDA $CD                         ; 4CE9: A5 CD  ; trackball_accum_y
    STY $CD                         ; 4CEB: 84 CD  ; trackball_accum_y
    JSR negate_a                    ; 4CED: 20 00 76
    JSR clamp_trackball             ; 4CF0: 20 83 60
    ADC $61                         ; 4CF3: 65 61  ; trackball_frac_y
    STA $61                         ; 4CF5: 85 61  ; trackball_frac_y
    TYA                             ; 4CF7: 98
    ADC $3F                         ; 4CF8: 65 3F  ; player_xpos
    TAX                             ; 4CFA: AA
    LDY $2F                         ; 4CFB: A4 2F  ; player_ypos
    STY $9B                         ; 4CFD: 84 9B  ; temp_9B
    LDY #$00                        ; 4CFF: A0 00
    JSR xy_to_vram                  ; 4D01: 20 9C 59
    BNE L4D2B                       ; 4D04: D0 25
    TXA                             ; 4D06: 8A
    CMP #$08                        ; 4D07: C9 08  ; left edge
    BCC L4D27                       ; 4D09: 90 1C  ; too far left
    CMP #$F1                        ; 4D0B: C9 F1  ; right edge
    BCS L4D23                       ; 4D0D: B0 14  ; too far right
    CMP #$80                        ; 4D0F: C9 80  ; right half of screen?
    BCC L4D1B                       ; 4D11: 90 08  ; no -> left half
    CMP #$C8                        ; 4D13: C9 C8  ; right: clamp at $C8
    BCS L4D2D                       ; 4D15: B0 16  ; in range -> ok
    LDA #$C8                        ; 4D17: A9 C8  ; clamp to $C8 (keep in zone)
    BNE L4D2D                       ; 4D19: D0 12

L4D1B:
    CMP #$31                        ; 4D1B: C9 31  ; left: clamp at $30
    BCC L4D2D                       ; 4D1D: 90 0E  ; in range -> ok
    LDA #$30                        ; 4D1F: A9 30  ; clamp to $30 (dead zone gap)
    BNE L4D2D                       ; 4D21: D0 0A

L4D23:
    LDA #$F0                        ; 4D23: A9 F0  ; right edge max
    BNE L4D2D                       ; 4D25: D0 06

L4D27:
    LDA #$08                        ; 4D27: A9 08  ; left edge min
    BNE L4D2D                       ; 4D29: D0 02

L4D2B:
    LDA $3F                         ; 4D2B: A5 3F  ; player_xpos

L4D2D:
    STA $3F                         ; 4D2D: 85 3F  ; player_xpos
    LDY $96                         ; 4D2F: A4 96  ; game_state
    BPL L4D34                       ; 4D31: 10 01
    RTS                             ; 4D33: 60

L4D34:
    LDA $3E                         ; 4D34: A5 3E
    CMP $9D                         ; 4D36: C5 9D
    BNE L4D46                       ; 4D38: D0 0C

; ------------------------------------------------------------
; ============================================================
; Save current player position to backup slots $3E/$2E and
; mark $5E = $FF as an invalidation sentinel (used by
; bullet/collision code to detect stale position data).
; ============================================================
save_player_pos_invalidate:
    LDA #$FF                        ; 4D3A: A9 FF  ; sentinel = invalid
    STA $5E                         ; 4D3C: 85 5E
    LDA $3F                         ; 4D3E: A5 3F  ; player_xpos -> backup
    STA $3E                         ; 4D40: 85 3E
    LDA $2F                         ; 4D42: A5 2F  ; player_ypos -> backup
    STA $2E                         ; 4D44: 85 2E

L4D46:
    RTS                             ; 4D46: 60

; ------------------------------------------------------------
check_field_collision:
    LDY #$00                        ; 4D47: A0 00
    LDA $00,X                       ; 4D49: B5 00
    CMP #$14                        ; 4D4B: C9 14
    BCC L4D55                       ; 4D4D: 90 06
    CMP #$1C                        ; 4D4F: C9 1C
    BCS L4D55                       ; 4D51: B0 02
    LDY #$80                        ; 4D53: A0 80

L4D55:
    LDA $2F                         ; 4D55: A5 2F  ; player_ypos
    SEC                             ; 4D57: 38
    SBC $20,X                       ; 4D58: F5 20
    EOR $F1                         ; 4D5A: 45 F1  ; x_flip_xor
    BPL L4D60                       ; 4D5C: 10 02
    EOR #$FF                        ; 4D5E: 49 FF

L4D60:
    INY                             ; 4D60: C8
    BPL L4D68                       ; 4D61: 10 05
    CMP #$0A                        ; 4D63: C9 0A
    BCC L4D6C                       ; 4D65: 90 05

L4D67:
    RTS                             ; 4D67: 60

L4D68:
    CMP #$06                        ; 4D68: C9 06
    BCS L4D67                       ; 4D6A: B0 FB

L4D6C:
    STA $9D                         ; 4D6C: 85 9D
    LDA $30,X                       ; 4D6E: B5 30
    SEC                             ; 4D70: 38
    SBC $3F                         ; 4D71: E5 3F  ; player_xpos
    EOR $F1                         ; 4D73: 45 F1  ; x_flip_xor
    BPL L4D79                       ; 4D75: 10 02
    EOR #$FF                        ; 4D77: 49 FF

L4D79:
    CMP #$06                        ; 4D79: C9 06
    BCS L4D67                       ; 4D7B: B0 EA
    INY                             ; 4D7D: C8
    BPL L4D81                       ; 4D7E: 10 01
    ASL A                           ; 4D80: 0A

L4D81:
    CLC                             ; 4D81: 18
    ADC $9D                         ; 4D82: 65 9D
    CMP #$0A                        ; 4D84: C9 0A
    BCS L4D67                       ; 4D86: B0 DF
    LDA $E4                         ; 4D88: A5 E4  ; dip_switch_2
    AND #$C3                        ; 4D8A: 29 C3
    CMP #$C0                        ; 4D8C: C9 C0
    BNE L4D94                       ; 4D8E: D0 04
    INY                             ; 4D90: C8
    SEC                             ; 4D91: 38
    BPL L4D67                       ; 4D92: 10 D3

L4D94:
    LDA #$10                        ; 4D94: A9 10
    STA $97                         ; 4D96: 85 97  ; wave_timer
    LDA $3E                         ; 4D98: A5 3E
    CMP $3F                         ; 4D9A: C5 3F  ; player_xpos
    BNE L4DA2                       ; 4D9C: D0 04
    LDA #$00                        ; 4D9E: A9 00
    STA $2E                         ; 4DA0: 85 2E

L4DA2:
    LDA #$60                        ; 4DA2: A9 60  ; 96 frames ~ 1.5 sec freeze
    STA $02CE                       ; 4DA4: 8D CE 02  ; freeze_timer
    TXA                             ; 4DA7: 8A
    LDX $98                         ; 4DA8: A6 98  ; current_player
    INC $FD,X                       ; 4DAA: F6 FD  ; p1_mush_destroyed
    TAX                             ; 4DAC: AA
    LDA #$00                        ; 4DAD: A9 00
    STA $F9                         ; 4DAF: 85 F9  ; swarm_active_cnt
    STA $02CA                       ; 4DB1: 8D CA 02  ; ddt_bombs_left
    STA $C8                         ; 4DB4: 85 C8  ; sound_effect_id
    STA $02CB                       ; 4DB6: 8D CB 02  ; death_timer
    STA $FC                         ; 4DB9: 85 FC  ; mushroom_deficit
    LDY #$09                        ; 4DBB: A0 09

L4DBD:
    STA $00C0,Y                     ; 4DBD: 99 C0 00  ; RAM
    DEY                             ; 4DC0: 88
    BPL L4DBD                       ; 4DC1: 10 FA
    CLC                             ; 4DC3: 18
    RTS                             ; 4DC4: 60

; ============================================================
; Bullet movement and collision detection. Moves the player's shot
; upward each frame, tests for hits against mushrooms and enemies.
; On mushroom hit: damages mushroom (4 hit stages -> destroy).
; On enemy hit: calls obj_collision_score for appropriate points.
; ============================================================
bullet_move_collide:
    LDA $0F                         ; 4DC5: A5 0F  ; player_tile
    EOR #$0A                        ; 4DC7: 49 0A
    ORA $02CE                       ; 4DC9: 0D CE 02  ; freeze_timer
    BEQ L4DCF                       ; 4DCC: F0 01
    RTS                             ; 4DCE: 60

L4DCF:
    LDA $5E                         ; 4DCF: A5 5E
    CMP #$FF                        ; 4DD1: C9 FF
    BNE L4DE4                       ; 4DD3: D0 0F
    LDA $3E                         ; 4DD5: A5 3E
    BIT $EF                         ; 4DD7: 24 EF  ; flip_screen
    BPL L4DE0                       ; 4DD9: 10 05
    CLC                             ; 4DDB: 18
    ADC #$07                        ; 4DDC: 69 07
    EOR #$FF                        ; 4DDE: 49 FF

L4DE0:
    CMP #$F2                        ; 4DE0: C9 F2
    BCC L4DE7                       ; 4DE2: 90 03

L4DE4:
    JSR save_player_pos_invalidate                    ; 4DE4: 20 3A 4D

L4DE7:
    LDA $3F                         ; 4DE7: A5 3F  ; player_xpos
    CMP $3E                         ; 4DE9: C5 3E
    BNE L4E08                       ; 4DEB: D0 1B
    LDA $2000                       ; 4DED: AD 00 20  ; IN0
    LDX $96                         ; 4DF0: A6 96  ; game_state
    BPL L4DF7                       ; 4DF2: 10 03
    JSR check_restore_milestone                    ; 4DF4: 20 3E 67

L4DF7:
    BIT $EF                         ; 4DF7: 24 EF  ; flip_screen
    BPL L4DFE                       ; 4DF9: 10 03
    LDA $2001                       ; 4DFB: AD 01 20  ; IN1

L4DFE:
    AND #$10                        ; 4DFE: 29 10
    BEQ L4E04                       ; 4E00: F0 02
    BNE L4E56                       ; 4E02: D0 52

L4E04:
    LDA #$0B                        ; 4E04: A9 0B
    STA $C6                         ; 4E06: 85 C6  ; bullet_speed

L4E08:
    JSR advance_bullet              ; 4E08: 20 C4 4E

L4E0B:
    BNE L4E52                       ; 4E0B: D0 45
    LDA #$07                        ; 4E0D: A9 07
    EOR $F2                         ; 4E0F: 45 F2  ; dir_flip_xor
    CLC                             ; 4E11: 18
    ADC $3E                         ; 4E12: 65 3E
    STA $3E                         ; 4E14: 85 3E
    LDX #$0D                        ; 4E16: A2 0D

L4E18:
    LDA $50,X                       ; 4E18: B5 50
    BEQ L4E48                       ; 4E1A: F0 2C
    LDA $30,X                       ; 4E1C: B5 30
    EOR $F0                         ; 4E1E: 45 F0  ; y_flip_xor
    CMP #$F4                        ; 4E20: C9 F4
    BCS L4E48                       ; 4E22: B0 24
    EOR $F0                         ; 4E24: 45 F0  ; y_flip_xor
    SEC                             ; 4E26: 38
    SBC $3E                         ; 4E27: E5 3E
    JSR abs_value_a                 ; 4E29: 20 FE 75
    CMP #$06                        ; 4E2C: C9 06
    BCS L4E48                       ; 4E2E: B0 18
    LDA $00,X                       ; 4E30: B5 00

L4E32:
    AND #$3F                        ; 4E32: 29 3F
    CMP #$3A                        ; 4E34: C9 3A
    BCS L4E48                       ; 4E36: B0 10
    LSR A                           ; 4E38: 4A
    LSR A                           ; 4E39: 4A
    TAY                             ; 4E3A: A8
    LDA $20,X                       ; 4E3B: B5 20
    SEC                             ; 4E3D: 38
    SBC $2E                         ; 4E3E: E5 2E
    JSR abs_value_a                 ; 4E40: 20 FE 75
    CMP $4E90,Y                     ; 4E43: D9 90 4E
    BCC L4E4D                       ; 4E46: 90 05

L4E48:
    DEX                             ; 4E48: CA
    BPL L4E18                       ; 4E49: 10 CD
    BMI L4E56                       ; 4E4B: 30 09

L4E4D:
    LDA #$00                        ; 4E4D: A9 00
    JSR apply_hit_score             ; 4E4F: 20 AA 4E

L4E52:
    LDA #$C3                        ; 4E52: A9 C3
    STA $5E                         ; 4E54: 85 5E

L4E56:
    LDX $98                         ; 4E56: A6 98  ; current_player
    LDA $A5,X                       ; 4E58: B5 A5  ; p1_lives
    ORA $97                         ; 4E5A: 05 97  ; wave_timer
    BNE L4E8F                       ; 4E5C: D0 31
    LDA #$40                        ; 4E5E: A9 40
    STA $97                         ; 4E60: 85 97  ; wave_timer
    INC $AD,X                       ; 4E62: F6 AD  ; p1_speed_level

L4E64:
    LDA $AD,X                       ; 4E64: B5 AD  ; p1_speed_level
    CMP #$03                        ; 4E66: C9 03
    BCC L4E8F                       ; 4E68: 90 25
    BNE L4E8F                       ; 4E6A: D0 23
    LDA $AB,X                       ; 4E6C: B5 AB  ; p1_segments
    CMP #$09                        ; 4E6E: C9 09
    BNE L4E75                       ; 4E70: D0 03
    JMP L685D                       ; 4E72: 4C 5D 68

L4E75:
    LDY #$04                        ; 4E75: A0 04

L4E77:
    CMP $43FA,Y                     ; 4E77: D9 FA 43
    BNE L4E8C                       ; 4E7A: D0 10
    LDA $BA,X                       ; 4E7C: B5 BA  ; p1_score_hi
    LSR A                           ; 4E7E: 4A
    ADC #$14                        ; 4E7F: 69 14
    STA $02CA                       ; 4E81: 8D CA 02  ; ddt_bombs_left
    INC $02CF                       ; 4E84: EE CF 02  ; bonus_mult_state
    LDA #$40                        ; 4E87: A9 40
    STA $97                         ; 4E89: 85 97  ; wave_timer
    RTS                             ; 4E8B: 60

L4E8C:
    DEY                             ; 4E8C: 88
    BPL L4E77                       ; 4E8D: 10 E8

L4E8F:
    RTS                             ; 4E8F: 60
    .byte $06,$06,$00,$08

L4E94:
    .byte $0A,$0A,$0A,$0A,$00,$00,$00,$00,$00,$06,$06,$00

; ------------------------------------------------------------
; Check if tile in A is a mushroom ($2E-$6D). C=1 if mushroom.
; Check if position is in mushroom-eligible range.
check_mushroom_range:
    CMP #$2E                        ; 4EA0: C9 2E  ; first mushroom tile
    BCC L4EC2                       ; 4EA2: 90 1E

L4EA4:
    CMP #$6E                        ; 4EA4: C9 6E  ; past last mushroom tile?
    BCS L4EC2                       ; 4EA6: B0 1A  ; $2E-$6D = mushroom body

; ------------------------------------------------------------
; Award points for hitting a mushroom.
hit_mushroom_score:
    LDA #$80                        ; 4EA8: A9 80

; ------------------------------------------------------------
; Apply score for bullet hit and update mushroom tile.
apply_hit_score:
    JSR obj_collision_score         ; 4EAA: 20 7D 4F
    BCC L4EC1                       ; 4EAD: 90 12
    STY $9B                         ; 4EAF: 84 9B  ; temp_9B
    JSR add_to_score                ; 4EB1: 20 E4 5A
    LDA #$14                        ; 4EB4: A9 14
    STA $C2                         ; 4EB6: 85 C2  ; mushroom_regen
    LDA #$FF                        ; 4EB8: A9 FF
    STA $00,X                       ; 4EBA: 95 00
    LDA #$F9                        ; 4EBC: A9 F9
    STA $50,X                       ; 4EBE: 95 50
    SEC                             ; 4EC0: 38

L4EC1:
    RTS                             ; 4EC1: 60

L4EC2:
    CLC                             ; 4EC2: 18
    RTS                             ; 4EC3: 60

; ------------------------------------------------------------
; Advance bullet position upward and check for hits.
advance_bullet:
    LDA $2E                         ; 4EC4: A5 2E
    STA $9B                         ; 4EC6: 85 9B  ; temp_9B
    LDA #$02                        ; 4EC8: A9 02
    BIT $EF                         ; 4ECA: 24 EF  ; flip_screen
    BPL L4ED0                       ; 4ECC: 10 02
    LDA #$FD                        ; 4ECE: A9 FD

L4ED0:
    CLC                             ; 4ED0: 18
    ADC $3E                         ; 4ED1: 65 3E
    LDY #$00                        ; 4ED3: A0 00
    JSR xy_to_vram                  ; 4ED5: 20 9C 59
    BEQ L4F4A                       ; 4ED8: F0 70  ; tile $00 = empty
    CMP #$2E                        ; 4EDA: C9 2E  ; tile < $2E? not mushroom
    BCC L4F1B                       ; 4EDC: 90 3D
    CMP #$6E                        ; 4EDE: C9 6E  ; $2E-$6D = mushroom body
    BCC L4F4A                       ; 4EE0: 90 68  ; bullet absorbed by mushroom
    BEQ L4F1E                       ; 4EE2: F0 3A  ; $6E = DDT left half
    CMP #$70                        ; 4EE4: C9 70  ; $6F = DDT right half
    BCC L4F24                       ; 4EE6: 90 3C
    CMP #$71                        ; 4EE8: C9 71  ; $70 = full mushroom top
    BCC L4F1B                       ; 4EEA: 90 2F  ; solid -> stop bullet
    SBC #$01                        ; 4EEC: E9 01  ; adjust for damage calc
    CMP #$7B                        ; 4EEE: C9 7B  ; poisoned mush fully damaged?
    BEQ L4EFE                       ; 4EF0: F0 0C  ; -> destroy it
    CMP #$77                        ; 4EF2: C9 77  ; healthy mush fully damaged?
    BEQ L4EFE                       ; 4EF4: F0 08  ; -> destroy it
    CMP #$74                        ; 4EF6: C9 74  ; healthy mush mid damage?
    BEQ L4EFE                       ; 4EF8: F0 04  ; -> destroy it
    CMP #$70                        ; 4EFA: C9 70  ; full mushroom?
    BNE L4F0A                       ; 4EFC: D0 0C  ; -> just damage it

L4EFE:
    LDA #$00                        ; 4EFE: A9 00
    STA $9B                         ; 4F00: 85 9B  ; temp_9B
    LDA #$01                        ; 4F02: A9 01
    JSR add_to_score                ; 4F04: 20 E4 5A
    LDY #$00                        ; 4F07: A0 00
    TYA                             ; 4F09: 98

L4F0A:
    STA $9B                         ; 4F0A: 85 9B  ; temp_9B
    LDA ($94),Y                     ; 4F0C: B1 94  ; [vram_ptr_lo]
    AND #$80                        ; 4F0E: 29 80
    ORA $9B                         ; 4F10: 05 9B  ; temp_9B
    STA ($94),Y                     ; 4F12: 91 94  ; [vram_ptr_lo]
    AND #$7F                        ; 4F14: 29 7F
    BNE L4F1B                       ; 4F16: D0 03
    JSR track_mushroom_column       ; 4F18: 20 D5 58

L4F1B:
    LDA #$01                        ; 4F1B: A9 01
    RTS                             ; 4F1D: 60

L4F1E:
    BIT $EF                         ; 4F1E: 24 EF  ; flip_screen
    BPL L4F33                       ; 4F20: 10 11
    BMI L4F28                       ; 4F22: 30 04

L4F24:
    BIT $EF                         ; 4F24: 24 EF  ; flip_screen
    BMI L4F33                       ; 4F26: 30 0B

L4F28:
    LDA $94                         ; 4F28: A5 94  ; vram_ptr_lo
    SEC                             ; 4F2A: 38
    SBC #$20                        ; 4F2B: E9 20
    STA $94                         ; 4F2D: 85 94  ; vram_ptr_lo
    BCS L4F33                       ; 4F2F: B0 02
    DEC $95                         ; 4F31: C6 95  ; vram_ptr_hi

L4F33:
    JSR get_player_obj_ptr          ; 4F33: 20 32 57

L4F36:
    LDA $02F0,X                     ; 4F36: BD F0 02  ; RAM
    CMP $95                         ; 4F39: C5 95  ; vram_ptr_hi

L4F3B:
    BNE L4F44                       ; 4F3B: D0 07
    LDA $02EF,X                     ; 4F3D: BD EF 02  ; RAM
    CMP $94                         ; 4F40: C5 94  ; vram_ptr_lo
    BEQ L4F4D                       ; 4F42: F0 09

L4F44:
    DEX                             ; 4F44: CA
    DEX                             ; 4F45: CA
    DEC $9D                         ; 4F46: C6 9D
    BPL L4F36                       ; 4F48: 10 EC

L4F4A:
    LDA #$00                        ; 4F4A: A9 00
    RTS                             ; 4F4C: 60

L4F4D:
    LDA #$00                        ; 4F4D: A9 00
    TAY                             ; 4F4F: A8
    LDA ($94),Y                     ; 4F50: B1 94  ; [vram_ptr_lo]
    AND #$80                        ; 4F52: 29 80
    STA ($94),Y                     ; 4F54: 91 94  ; [vram_ptr_lo]
    LDY #$20                        ; 4F56: A0 20
    STA ($94),Y                     ; 4F58: 91 94  ; [vram_ptr_lo]
    LDA $94                         ; 4F5A: A5 94  ; vram_ptr_lo
    SEC                             ; 4F5C: 38

L4F5D:
    SBC #$61                        ; 4F5D: E9 61
    STA $02EF,X                     ; 4F5F: 9D EF 02  ; RAM
    LDA $95                         ; 4F62: A5 95  ; vram_ptr_hi
    SBC #$00                        ; 4F64: E9 00
    ORA #$B4                        ; 4F66: 09 B4
    STA $02F0,X                     ; 4F68: 9D F0 02  ; RAM
    LDA #$08                        ; 4F6B: A9 08

L4F6D:
    STA $9B                         ; 4F6D: 85 9B  ; temp_9B
    LDA #$00                        ; 4F6F: A9 00
    JSR add_to_score                ; 4F71: 20 E4 5A
    LDX $98                         ; 4F74: A6 98  ; current_player
    INC $FD,X                       ; 4F76: F6 FD  ; p1_mush_destroyed
    LDA #$24                        ; 4F78: A9 24
    STA $C2                         ; 4F7A: 85 C2  ; mushroom_regen
    RTS                             ; 4F7C: 60

; ============================================================
; Object collision/scoring. Given object in slot X, determines what
; was hit based on tile code. Returns score in Y. Handles:
;   millipede body->head promotion, spider proximity scoring,
;   mushroom damage, DDT chain reactions.
; ============================================================
obj_collision_score:
    STA $A0                         ; 4F7D: 85 A0  ; collision_mode ($00=bullet, $80=field)
    LDA $00,X                       ; 4F7F: B5 00  ; get tile ID
    AND #$3F                        ; 4F81: 29 3F  ; mask off color bits
    CMP #$08                        ; 4F83: C9 08  ; $00-$07 = millipede body
    BCC L5005                       ; 4F85: 90 7E  ; -> millipede hit
