    ROL $95                         ; 59BC: 26 95  ; vram_ptr_hi
    ASL A                           ; 59BE: 0A
    ROL $95                         ; 59BF: 26 95  ; vram_ptr_hi
    ORA $94                         ; 59C1: 05 94  ; vram_ptr_lo
    LDY $95                         ; 59C3: A4 95  ; vram_ptr_hi
    CPY #$13                        ; 59C5: C0 13

