; Apply velocity stored at $0381/$0382 to object in slot X.
; Adds Y-delta to $20,X and X-delta to $30,X.
; ------------------------------------------------------------
apply_object_velocity:
    LDA $20,X                       ; 6553: B5 20  ; obj Y position
    CLC                             ; 6555: 18
    ADC $0381                       ; 6556: 6D 81 03  ; RAM = Y velocity delta
    STA $20,X                       ; 6559: 95 20  ; update Y position
    LDA $30,X                       ; 655B: B5 30  ; obj X position
    CLC                             ; 655D: 18
    ADC $0382                       ; 655E: 6D 82 03  ; RAM = X velocity delta
    STA $30,X                       ; 6561: 95 30  ; update X position
    RTS                             ; 6563: 60

