; ============================================================
; Sound engine update. Called from IRQ handler during VBLANK.
; Processes POKEY sound channel state for all active effects.
; ============================================================
sound_engine_update:
    LDX #$0B                        ; 6BC7: A2 0B  ; 12 sound channels (0-11)

L6BC9:                                              ; --- process channel X ---
    LDA $C0,X                       ; 6BC9: B5 C0  ; swarm_timer = channel duration
    BMI L6BDE                       ; 6BCB: 30 11
    LDA $6C55,X                     ; 6BCD: BD 55 6C  ; channel gate mask
