; ============================================================
; Display text by index. Maps index A -> pointer from table at
; $7454 -> writes string to VRAM. Bit 7 of last char = terminator.
; ============================================================
display_text_by_idx:
    ASL A                           ; 73EB: 0A    ; index * 2 (bit 7 -> carry -> $9C)
    ROR $9C                         ; 73EC: 66 9C  ; temp_9C - save char mode bit
    ASL A                           ; 73EE: 0A    ; index * 4
    STA $9B                         ; 73EF: 85 9B  ; temp_9B
    LDA $F8                         ; 73F1: A5 F8  ; combined_dip bits 0-1 = language
    AND #$03                        ; 73F3: 29 03  ; 0=English, 1=German, 2=French, 3=Spanish
    ORA $9B                         ; 73F5: 05 9B  ; temp_9B - combine with index*4

L73F7:                                              ; --- look up string from pointer table ---
    ASL A                           ; 73F7: 0A    ; * 2 for 16-bit pointer
    TAX                             ; 73F8: AA
    LDA $7454,X                     ; 73F9: BD 54 74  ; string pointer table (low byte)
    STA $A3                         ; 73FC: 85 A3  ; string_ptr_lo
    LDA $7455,X                     ; 73FE: BD 55 74  ; string pointer table (high byte)
    STA $A4                         ; 7401: 85 A4  ; string_ptr_hi
    LDY #$00                        ; 7403: A0 00
    LDA ($A3),Y                     ; 7405: B1 A3  ; [string_ptr_lo] byte 0 = VRAM col
    TAX                             ; 7407: AA
    INY                             ; 7408: C8
    LDA ($A3),Y                     ; 7409: B1 A3  ; [string_ptr_lo] byte 1 = VRAM page
    BIT $EF                         ; 740B: 24 EF  ; flip_screen
    BPL L741D                       ; 740D: 10 0E  ; not flipped -> use as-is
    STA $A2                         ; 740F: 85 A2  ; text_ptr_hi
    STX $A1                         ; 7411: 86 A1  ; text_ptr_lo
    LDA #$BF                        ; 7413: A9 BF
    SEC                             ; 7415: 38
    SBC $A1                         ; 7416: E5 A1  ; text_ptr_lo
    TAX                             ; 7418: AA
    LDA #$03                        ; 7419: A9 03
    SBC $A2                         ; 741B: E5 A2  ; text_ptr_hi

L741D:
    ORA #$10                        ; 741D: 09 10
    STX $A1                         ; 741F: 86 A1  ; text_ptr_lo
    STA $A2                         ; 7421: 85 A2  ; text_ptr_hi
    INY                             ; 7423: C8

L7424:
    STY $9B                         ; 7424: 84 9B  ; temp_9B

L7426:                                              ; --- render string character loop ---
    LDY $9B                         ; 7426: A4 9B  ; temp_9B = string offset
    LDA ($A3),Y                     ; 7428: B1 A3  ; [string_ptr_lo] read next char
    AND #$3F                        ; 742A: 29 3F  ; mask to 6-bit char code
    CMP #$20                        ; 742C: C9 20  ; space character?
    BEQ L7434                       ; 742E: F0 04  ; yes -> write blank tile
    LDX $9C                         ; 7430: A6 9C  ; temp_9C - char mode (erase vs draw)
    BPL L7436                       ; 7432: 10 02  ; mode >= 0 -> draw normally

L7434:
    LDA #$00                        ; 7434: A9 00

L7436:
    CMP #$30                        ; 7436: C9 30
    BCC L743C                       ; 7438: 90 02
    AND #$2F                        ; 743A: 29 2F

L743C:
    JSR write_tile_vram             ; 743C: 20 09 76  ; write char tile to VRAM
    LDY $9B                         ; 743F: A4 9B  ; temp_9B
    INC $9B                         ; 7441: E6 9B  ; temp_9B - advance to next char
    LDA ($A3),Y                     ; 7443: B1 A3  ; [string_ptr_lo] re-read for terminator
    BPL L7426                       ; 7445: 10 DF  ; bit 7 clear -> more chars
    RTS                             ; 7447: 60    ; bit 7 set -> end of string

