; ============================================================
; IRQ handler (VBLANK, ~61 Hz). Saves registers, checks VBLANK via
; IN0 bit 6. If VBLANK: sets vblank_flag, increments frame timer,
; reads trackball/joystick input, copies 16 object slots to sprite
; RAM ($13C0-$13FF), calls sound engine. Acknowledges IRQ at $2600.
; ============================================================
IRQ_handler:
    PHA                             ; 7643: 48
    TXA                             ; 7644: 8A
    PHA                             ; 7645: 48
    TYA                             ; 7646: 98
    PHA                             ; 7647: 48
    CLD                             ; 7648: D8
    BIT $2000                       ; 7649: 2C 00 20  ; IN0
    BVS L7651                       ; 764C: 70 03
    JMP L76FA                       ; 764E: 4C FA 76

L7651:
    INC $9A                         ; 7651: E6 9A  ; vblank_flag
    LDA $E5                         ; 7653: A5 E5  ; game_flags
    ORA #$03                        ; 7655: 09 03
    STA $E5                         ; 7657: 85 E5  ; game_flags
    INC $62                         ; 7659: E6 62  ; timer_lo
    BNE L766E                       ; 765B: D0 11
    INC $63                         ; 765D: E6 63  ; timer_hi
    SED                             ; 765F: F8
    LDA $F5                         ; 7660: A5 F5  ; play_timer_lo
    CLC                             ; 7662: 18
    ADC #$01                        ; 7663: 69 01
    STA $F5                         ; 7665: 85 F5  ; play_timer_lo
    LDA $F6                         ; 7667: A5 F6  ; play_timer_hi
    ADC #$00                        ; 7669: 69 00
    STA $F6                         ; 766B: 85 F6  ; play_timer_hi
    CLD                             ; 766D: D8

L766E:
    LDA $9A                         ; 766E: A5 9A  ; vblank_flag
    CMP #$08                        ; 7670: C9 08  ; >8 vblanks missed = hung

L7672:
    BCS L7672                       ; 7672: B0 FE  ; <<< SPIN LOOP: trigger watchdog reset
    LDA $D9                         ; 7674: A5 D9  ; credit_count
    CMP #$25                        ; 7676: C9 25  ; >25 credits = corrupted

L7678:
    BCS L7678                       ; 7678: B0 FE  ; <<< SPIN LOOP (safety/watchdog catch)
    CMP #$13                        ; 767A: C9 13
    BCC L7682                       ; 767C: 90 04
    LDA #$12                        ; 767E: A9 12
    STA $D9                         ; 7680: 85 D9  ; credit_count

L7682:
    LDA $2010                       ; 7682: AD 10 20  ; IN2
    LDY $02C8                       ; 7685: AC C8 02  ; trackball_state_x
    JSR quadrature_decode           ; 7688: 20 D2 77
    STY $02C8                       ; 768B: 8C C8 02  ; trackball_state_x
    PHA                             ; 768E: 48
    TYA                             ; 768F: 98
    CLC                             ; 7690: 18
    ADC $CC                         ; 7691: 65 CC  ; trackball_accum_x
    STA $CC                         ; 7693: 85 CC  ; trackball_accum_x
    PLA                             ; 7695: 68
    LDY $02C9                       ; 7696: AC C9 02  ; trackball_state_y
    JSR quadrature_decode           ; 7699: 20 D2 77
    STY $02C9                       ; 769C: 8C C9 02  ; trackball_state_y
    TYA                             ; 769F: 98
    JSR negate_a                    ; 76A0: 20 00 76
    CLC                             ; 76A3: 18
    ADC $CD                         ; 76A4: 65 CD  ; trackball_accum_y
    STA $CD                         ; 76A6: 85 CD  ; trackball_accum_y
    LDX #$0F                        ; 76A8: A2 0F  ; 16 sprite slots (0-$0F)

; Copy all 16 object slots to sprite RAM for display
L76AA:
    LDA $30,X                       ; 76AA: B5 30  ; Y position -> sprite Y
    STA $13E0,X                     ; 76AC: 9D E0 13  ; Sprite RAM Y coords
    LDA $20,X                       ; 76AF: B5 20  ; X position -> sprite X
    STA $13D0,X                     ; 76B1: 9D D0 13  ; Sprite RAM X coords
    LDA $10,X                       ; 76B4: B5 10  ; X speed (sign = flip bit)
    EOR $F1                         ; 76B6: 45 F1  ; x_flip_xor (cocktail mode)
    AND #$80                        ; 76B8: 29 80  ; isolate horizontal flip
    STA $A8                         ; 76BA: 85 A8  ; temp_flip
    LDA $00,X                       ; 76BC: B5 00  ; tile ID
    BIT $2011                       ; 76BE: 2C 11 20  ; IN3 (cocktail cabinet?)
    BPL L76E7                       ; 76C1: 10 24  ; upright -> skip fixup
    CMP #$08                        ; 76C3: C9 08  ; tile < $08? millipede body
    BCS L76E5                       ; 76C5: B0 1E  ; >= $08, use tile as-is

L76C7:
