; ============================================================
; EAROM read all. Reads 27 bytes from EAROM chip into shadow
; buffer at $0288-$02A2 (high scores, initials, bookkeeping).
; Loops X=26..0, calling earom_read_byte for each address.
; ============================================================
earom_read_all:
    LDX #$1A                        ; 78BE: A2 1A

L78C0:
    JSR earom_read_byte             ; 78C0: 20 CC 78
    STA $0288,X                     ; 78C3: 9D 88 02  ; earom_shadow
    DEX                             ; 78C6: CA
    BPL L78C0                       ; 78C7: 10 F7
    STX $F3                         ; 78C9: 86 F3  ; earom_write_idx

L78CB:
    RTS                             ; 78CB: 60

; ============================================================
; Read one EAROM byte. Address in X is latched via $2780,X.
; Sequences the ER2055 control lines through $2700 (EAROM_CTRL):
;   $08 = CS1+READ mode, CK=0   (select chip, read mode)
;   $09 = CS1+READ mode, CK=1   (clock high -- latch data)
;   $08 = CS1+READ mode, CK=0   (clock low -- complete pulse)
;   Read $2030 (EAROM_READ) to get the data byte
;   $00 = deselect chip (standby)
; ER2055 control bits: b0=CK, b1=/C1, b2=C2, b3=CS1
;   C1=1,C2=0 = READ | C1=0,C2=1 = WRITE | C1=0,C2=0 = STANDBY
; ============================================================
earom_read_byte:
    STA $2780,X                     ; 78CC: 9D 80 27  ; EAROM_WRITE addr
    LDY #$08                        ; 78CF: A0 08
    STY $2700                       ; 78D1: 8C 00 27  ; EAROM_CTRL: CS1+READ, CK=0
    INY                             ; 78D4: C8
    STY $2700                       ; 78D5: 8C 00 27  ; EAROM_CTRL: CS1+READ, CK=1
    DEY                             ; 78D8: 88
    STY $2700                       ; 78D9: 8C 00 27  ; EAROM_CTRL: CS1+READ, CK=0

L78DC:
    LDY #$00                        ; 78DC: A0 00
    LDA $2030                       ; 78DE: AD 30 20  ; EAROM_READ
    STY $2700                       ; 78E1: 8C 00 27  ; EAROM_CTRL: deselect
    RTS                             ; 78E4: 60

; ============================================================
; Incremental EAROM save. Called every frame; only acts every 4th.
; If earom_dirty ($F4) has bits set, commits the current byte to
; the ER2055 EAROM chip via the control sequence at $2700:
;   $00 = idle/deselect
;   $02 = /C1=0,C2=0 -- standby mode setup
;   $0A = CS1+standby -- triggers internal store cycle
; On verify failure (read-back mismatch), re-writes via:
;   $06 = C2=1,/C1=0 -- write mode setup
;   Write address+data to $2780,X (EAROM_WRITE)
;   $0E = CS1+C2=1,/C1=0 -- write mode, chip selected (commit)
; ============================================================
earom_save:
    LDA $62                         ; 78E5: A5 62  ; timer_lo
    AND #$03                        ; 78E7: 29 03
    BNE L7902                       ; 78E9: D0 17
    STA $2700                       ; 78EB: 8D 00 27  ; EAROM_CTRL: idle/deselect
    LDX $F3                         ; 78EE: A6 F3  ; earom_write_idx
    BMI L7902                       ; 78F0: 30 10
    LSR $F4                         ; 78F2: 46 F4  ; earom_dirty
    BCC L7903                       ; 78F4: 90 0D
    LDA #$02                        ; 78F6: A9 02
    STA $2700                       ; 78F8: 8D 00 27  ; EAROM_CTRL: standby setup
    LDA #$0A                        ; 78FB: A9 0A
    STA $2700                       ; 78FD: 8D 00 27  ; EAROM_CTRL: CS1+standby=store
    DEC $F3                         ; 7900: C6 F3  ; earom_write_idx

L7902:
    RTS                             ; 7902: 60

L7903:
    SEI                             ; 7903: 78

L7904:
    JSR earom_read_byte             ; 7904: 20 CC 78
    CMP $0288,X                     ; 7907: DD 88 02  ; earom_shadow
    BNE L7913                       ; 790A: D0 07
    DEX                             ; 790C: CA
    BPL L7904                       ; 790D: 10 F5
    CLI                             ; 790F: 58
    STX $F3                         ; 7910: 86 F3  ; earom_write_idx
    RTS                             ; 7912: 60

L7913:
    CLI                             ; 7913: 58
    STX $F3                         ; 7914: 86 F3  ; earom_write_idx
    LDA #$06                        ; 7916: A9 06
    STA $2700                       ; 7918: 8D 00 27  ; EAROM_CTRL: write mode setup
    LDA $0288,X                     ; 791B: BD 88 02  ; earom_shadow
    STA $2780,X                     ; 791E: 9D 80 27  ; EAROM_WRITE addr+data
    LDA #$0E                        ; 7921: A9 0E
    STA $2700                       ; 7923: 8D 00 27  ; EAROM_CTRL: CS1+write=commit
    INC $F4                         ; 7926: E6 F4  ; earom_dirty
    RTS                             ; 7928: 60

; ============================================================
; Hardware RESET. SEI/CLD, stack=$FF. Clears all RAM ($0000-$03FF)
