    DEX                             ; 7A42: CA    ; X = $FF
    STX $96                         ; 7A43: 86 96  ; game_state = $FF (attract mode)
    STX $D3                         ; 7A45: 86 D3  ; p1_active = $FF (inactive)
    STX $D4                         ; 7A47: 86 D4  ; p2_active = $FF (inactive)
    LDA $2011                       ; 7A49: AD 11 20  ; IN3 bit 7 = VBLANK
    BPL L7A77                       ; 7A4C: 10 29  ; if no VBLANK -> self-test check
