; ------------------------------------------------------------
; ============================================================
; Read DIP switches and trackball. Combines IN0 low nibble with
; IN1 high nibble into $F8 (combined_dip). Also captures
; trackball position into $D0/$D1 for delta tracking.
; A=$00 on entry to enable trackball reading, A=$FF to disable.
; ============================================================
read_dipsw_trackball:
    STA $2507                       ; 7FA2: 8D 07 25  ; OUT_INT_ACK - ack/reset interrupt
    LDA #$00                        ; 7FA5: A9 00
    STA $2505                       ; 7FA7: 8D 05 25  ; OUT_TBEN - disable trackball

L7FAA:                                              ; --- read combined DIP switch state ---
    LDA $2001                       ; 7FAA: AD 01 20  ; IN1 - player 2 inputs + DIP high
    ASL A                           ; 7FAD: 0A    ; shift high nibble of IN1
    ASL A                           ; 7FAE: 0A
    ASL A                           ; 7FAF: 0A
    ASL A                           ; 7FB0: 0A    ; into bits 4-7
    STA $F8                         ; 7FB1: 85 F8  ; combined_dip
    LDA $2000                       ; 7FB3: AD 00 20  ; IN0 - player 1 inputs + DIP low
    AND #$0F                        ; 7FB6: 29 0F  ; low nibble = language + options
    ORA $F8                         ; 7FB8: 05 F8  ; combined_dip - merge both halves
    STA $F8                         ; 7FBA: 85 F8  ; combined_dip
    STA $66                         ; 7FBC: 85 66  ; shadow copy
    LDA #$FF                        ; 7FBE: A9 FF
    STA $2505                       ; 7FC0: 8D 05 25  ; OUT_TBEN - enable trackball
    LDA $2000                       ; 7FC3: AD 00 20  ; IN0 - trackball X counter
    STA $D0                         ; 7FC6: 85 D0  ; trackball_prev_x
    LDA $2001                       ; 7FC8: AD 01 20  ; IN1 - trackball Y counter
    STA $D1                         ; 7FCB: 85 D1  ; trackball_prev_y
    RTS                             ; 7FCD: 60
    .byte $FF,$F8,$E7,$1F,$FE,$F9,$EF,$3F,$FD,$FA,$F7,$5F,$FC,$FB,$FF,$7F ; $7FCE
    .byte $00,$21,$41,$42,$51,$31,$00,$00,$20,$50,$4C,$41,$59,$D3,$20,$47 ; $7FDE
    .byte $41,$4D,$45,$20,$54,$49,$4D,$C5

